def select_action(obs: np.ndarray) -> int:
    """Select a Pong action from the 128-byte RAM state.

    The player controls the right paddle. A point is scored each time
    the ball passes the opponent's paddle; a point is lost when the
    ball passes the player's own paddle.

    Args:
        obs: 128-element uint8 array (ALE RAM).
            obs[49]: ball x  (17-160, left to right)
            obs[54]: ball y  (17-194, larger = lower on screen)
            obs[51]: player (right) paddle y center (34-194)
            obs[50]: CPU (left) paddle y center     (34-194)
    Returns:
        action: 0 (NOOP), 2 (UP), or 3 (DOWN)
    """
    ball_x = obs[49]
    ball_y = obs[54]
    paddle_y = obs[51]

    ball_vx = obs[52]
    if ball_vx > 127:
        vx = ball_vx - 256
    else:
        vx = ball_vx

    ball_vy = obs[53]
    if ball_vy > 127:
        vy = ball_vy - 256
    else:
        vy = ball_vy

    # Predict intercept only when ball is moving toward paddle
    if vx > 0:
        dx = 160 - ball_x
        if dx > 0:
            time_to_reach = dx / abs(vx)
            predicted_y = ball_y + int(vy * time_to_reach)
            # Account for wall bounces by reflecting within bounds
            while predicted_y < 17 or predicted_y > 194:
                if predicted_y < 17:
                    predicted_y = 17 + (17 - predicted_y)
                if predicted_y > 194:
                    predicted_y = 194 - (predicted_y - 194)
        else:
            predicted_y = ball_y
    else:
        # Ball moving away; just track current position
        predicted_y = ball_y

    predicted_y = max(34, min(194, predicted_y))

    # Proportional control: faster movement for larger error
    error = predicted_y - paddle_y
    if abs(error) > 5:
        if error > 0:
            return 3  # DOWN
        else:
            return 2  # UP
    elif abs(error) > 2:
        if error > 0:
            return 3
        else:
            return 2
    return 0  # NOOP

